CREATE TABLE IF NOT EXISTS courses ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, title TEXT NOT NULL, description TEXT, language_code TEXT NOT NULL, difficulty_level INTEGER DEFAULT 1, estimated_hours INTEGER, icon_url TEXT, color_hex TEXT, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS lessons ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, course_id UUID REFERENCES courses(id) ON DELETE CASCADE, title TEXT NOT NULL, description TEXT, content JSONB NOT NULL, difficulty_level INTEGER DEFAULT 1, prerequisites UUID[] DEFAULT '{}', estimated_duration INTEGER, lesson_type TEXT CHECK (lesson_type IN ('vocabulary', 'grammar', 'conversation', 'listening', 'reading', 'writing', 'mixed')), xp_reward INTEGER DEFAULT 10, gem_reward INTEGER DEFAULT 0, order_index INTEGER NOT NULL, is_active BOOLEAN DEFAULT true, cultural_notes TEXT, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS vocabulary ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, course_id UUID REFERENCES courses(id) ON DELETE CASCADE, word TEXT NOT NULL, translation TEXT NOT NULL, pronunciation_ipa TEXT, part_of_speech TEXT, gender TEXT, difficulty_level INTEGER DEFAULT 1, example_sentences JSONB DEFAULT '[]', mnemonic TEXT, etymology TEXT, image_url TEXT, audio_url TEXT, tags TEXT[] DEFAULT '{}', category TEXT, frequency_rank INTEGER, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS grammar_rules ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, course_id UUID REFERENCES courses(id) ON DELETE CASCADE, title TEXT NOT NULL, explanation TEXT NOT NULL, rule_category TEXT NOT NULL, difficulty_level INTEGER DEFAULT 1, visual_diagram JSONB, examples JSONB DEFAULT '[]', exceptions JSONB DEFAULT '[]', exercises JSONB DEFAULT '[]', related_lessons UUID[] DEFAULT '{}', created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS stories ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, course_id UUID REFERENCES courses(id) ON DELETE CASCADE, title TEXT NOT NULL, description TEXT, content JSONB NOT NULL, difficulty_level INTEGER DEFAULT 1, story_type TEXT CHECK (story_type IN ('interactive', 'dialogue', 'cultural', 'comic')), cultural_context TEXT, characters JSONB DEFAULT '[]', vocabulary_focus UUID[] DEFAULT '{}', grammar_focus UUID[] DEFAULT '{}', estimated_duration INTEGER, thumbnail_url TEXT, is_branching BOOLEAN DEFAULT false, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS practice_scenarios ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, course_id UUID REFERENCES courses(id) ON DELETE CASCADE, title TEXT NOT NULL, category TEXT NOT NULL, difficulty_level INTEGER DEFAULT 1, description TEXT, dialogues JSONB NOT NULL, cultural_tips JSONB DEFAULT '[]', vocabulary_introduced UUID[] DEFAULT '{}', expected_duration INTEGER, image_url TEXT, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS user_learning_profiles ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, learning_style TEXT CHECK (learning_style IN ('visual', 'auditory', 'kinesthetic', 'reading_writing', 'mixed')), adaptive_difficulty_level INTEGER DEFAULT 1, daily_goal_minutes INTEGER DEFAULT 15, daily_goal_xp INTEGER DEFAULT 50, weekly_goal_days INTEGER DEFAULT 5, preferred_study_time TIME, weak_areas JSONB DEFAULT '[]', strong_areas JSONB DEFAULT '[]', interests JSONB DEFAULT '[]', last_lesson_completed_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id) ); CREATE TABLE IF NOT EXISTS user_lessons ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, lesson_id UUID REFERENCES lessons(id) ON DELETE CASCADE, progress_percentage INTEGER DEFAULT 0, is_completed BOOLEAN DEFAULT false, score INTEGER, attempts INTEGER DEFAULT 0, time_spent_seconds INTEGER DEFAULT 0, started_at TIMESTAMP WITH TIME ZONE, completed_at TIMESTAMP WITH TIME ZONE, last_accessed_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), mistakes_made JSONB DEFAULT '[]', strengths_shown JSONB DEFAULT '[]', UNIQUE(user_id, lesson_id) ); CREATE TABLE IF NOT EXISTS user_vocabulary ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, vocabulary_id UUID REFERENCES vocabulary(id) ON DELETE CASCADE, mastery_level INTEGER DEFAULT 0 CHECK (mastery_level BETWEEN 0 AND 5), next_review_at TIMESTAMP WITH TIME ZONE, last_reviewed_at TIMESTAMP WITH TIME ZONE, review_count INTEGER DEFAULT 0, correct_count INTEGER DEFAULT 0, incorrect_count INTEGER DEFAULT 0, ease_factor REAL DEFAULT 2.5, interval_days INTEGER DEFAULT 1, is_learned BOOLEAN DEFAULT false, learned_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, vocabulary_id) ); CREATE TABLE IF NOT EXISTS user_grammar_progress ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, grammar_rule_id UUID REFERENCES grammar_rules(id) ON DELETE CASCADE, mastery_percentage INTEGER DEFAULT 0, is_mastered BOOLEAN DEFAULT false, exercises_completed INTEGER DEFAULT 0, exercises_correct INTEGER DEFAULT 0, mistakes JSONB DEFAULT '[]', last_practiced_at TIMESTAMP WITH TIME ZONE, mastered_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, grammar_rule_id) ); CREATE TABLE IF NOT EXISTS user_stories ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, story_id UUID REFERENCES stories(id) ON DELETE CASCADE, progress JSONB DEFAULT '{}', is_completed BOOLEAN DEFAULT false, score INTEGER, choices_made JSONB DEFAULT '[]', ending_reached TEXT, time_spent_seconds INTEGER DEFAULT 0, completed_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, story_id) ); CREATE TABLE IF NOT EXISTS user_scenario_attempts ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, scenario_id UUID REFERENCES practice_scenarios(id) ON DELETE CASCADE, score INTEGER, stars_earned INTEGER CHECK (stars_earned BETWEEN 0 AND 3), transcript JSONB DEFAULT '[]', feedback TEXT, accuracy_percentage INTEGER, completed_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS pronunciation_attempts ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, word_or_phrase TEXT NOT NULL, audio_url TEXT, score INTEGER CHECK (score BETWEEN 0 AND 100), accuracy_score INTEGER, fluency_score INTEGER, completeness_score INTEGER, pronunciation_feedback JSONB, target_language TEXT NOT NULL, native_language TEXT, attempted_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS user_streaks ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, current_streak INTEGER DEFAULT 0, longest_streak INTEGER DEFAULT 0, streak_freeze_count INTEGER DEFAULT 0, last_streak_date DATE, streak_history JSONB DEFAULT '[]', freeze_used_dates DATE[] DEFAULT '{}', is_weekend_protection_enabled BOOLEAN DEFAULT false, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id) ); CREATE TABLE IF NOT EXISTS streak_recovery_challenges ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, challenge_type TEXT NOT NULL, requirements JSONB NOT NULL, is_completed BOOLEAN DEFAULT false, completed_at TIMESTAMP WITH TIME ZONE, streak_restored BOOLEAN DEFAULT false, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), expires_at TIMESTAMP WITH TIME ZONE NOT NULL ); CREATE TABLE IF NOT EXISTS daily_quests ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, quest_date DATE NOT NULL, quests JSONB NOT NULL, completed_quests JSONB DEFAULT '[]', claimed_rewards BOOLEAN DEFAULT false, total_xp_earned INTEGER DEFAULT 0, total_gems_earned INTEGER DEFAULT 0, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, quest_date) ); CREATE TABLE IF NOT EXISTS quest_definitions ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, title TEXT NOT NULL, description TEXT NOT NULL, quest_type TEXT NOT NULL, requirement_value INTEGER NOT NULL, reward_xp INTEGER DEFAULT 10, reward_gems INTEGER DEFAULT 0, difficulty TEXT CHECK (difficulty IN ('easy', 'medium', 'hard')), is_active BOOLEAN DEFAULT true, icon_name TEXT, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS achievements ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, achievement_id TEXT NOT NULL, unlocked_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), tier TEXT CHECK (tier IN ('bronze', 'silver', 'gold', 'platinum')), progress_percentage INTEGER DEFAULT 100, is_new BOOLEAN DEFAULT true, viewed_at TIMESTAMP WITH TIME ZONE ); CREATE TABLE IF NOT EXISTS achievement_definitions ( id TEXT PRIMARY KEY, title TEXT NOT NULL, description TEXT NOT NULL, category TEXT NOT NULL, icon_url TEXT, tiers JSONB NOT NULL, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS weekly_challenges ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, week_start_date DATE NOT NULL, week_end_date DATE NOT NULL, title TEXT NOT NULL, description TEXT, challenge_type TEXT NOT NULL, requirements JSONB NOT NULL, reward_xp INTEGER, reward_gems INTEGER, reward_badge_id TEXT, participants_count INTEGER DEFAULT 0, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS user_weekly_challenges ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, challenge_id UUID REFERENCES weekly_challenges(id) ON DELETE CASCADE, current_progress INTEGER DEFAULT 0, target_progress INTEGER NOT NULL, is_completed BOOLEAN DEFAULT false, completed_at TIMESTAMP WITH TIME ZONE, rank INTEGER, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, challenge_id) ); CREATE TABLE IF NOT EXISTS ai_conversations ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, session_id TEXT NOT NULL, message TEXT NOT NULL, response TEXT NOT NULL, context_type TEXT, context_id UUID, language_code TEXT, message_tokens INTEGER, response_tokens INTEGER, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS ai_conversation_sessions ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, session_id TEXT UNIQUE NOT NULL, session_type TEXT NOT NULL, context JSONB, message_count INTEGER DEFAULT 0, started_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), last_message_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), is_active BOOLEAN DEFAULT true ); CREATE TABLE IF NOT EXISTS learning_analytics ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, date DATE NOT NULL, study_time_minutes INTEGER DEFAULT 0, lessons_completed INTEGER DEFAULT 0, words_learned INTEGER DEFAULT 0, words_reviewed INTEGER DEFAULT 0, xp_earned INTEGER DEFAULT 0, gems_earned INTEGER DEFAULT 0, accuracy_rate REAL, weak_areas JSONB DEFAULT '[]', strong_areas JSONB DEFAULT '[]', activities_breakdown JSONB DEFAULT '{}', created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, date) ); CREATE TABLE IF NOT EXISTS weekly_reports ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, week_start_date DATE NOT NULL, week_end_date DATE NOT NULL, total_study_time INTEGER, total_lessons INTEGER, total_words INTEGER, average_accuracy REAL, streak_maintained BOOLEAN, goals_achieved JSONB, recommendations JSONB, comparison_with_friends JSONB, generated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), viewed_at TIMESTAMP WITH TIME ZONE, UNIQUE(user_id, week_start_date) ); CREATE TABLE IF NOT EXISTS skill_heatmap ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, skill_category TEXT NOT NULL, subcategory TEXT NOT NULL, mastery_percentage INTEGER DEFAULT 0, last_practiced_at TIMESTAMP WITH TIME ZONE, practice_count INTEGER DEFAULT 0, updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, skill_category, subcategory) ); CREATE TABLE IF NOT EXISTS friend_activities ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, activity_type TEXT NOT NULL, activity_data JSONB NOT NULL, is_public BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS activity_likes ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, activity_id UUID REFERENCES friend_activities(id) ON DELETE CASCADE, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(activity_id, user_id) ); CREATE TABLE IF NOT EXISTS activity_comments ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, activity_id UUID REFERENCES friend_activities(id) ON DELETE CASCADE, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, comment TEXT NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS live_games ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, host_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, game_type TEXT NOT NULL, game_code TEXT UNIQUE NOT NULL, title TEXT, description TEXT, language_code TEXT NOT NULL, difficulty_level INTEGER DEFAULT 1, max_players INTEGER DEFAULT 4, current_players INTEGER DEFAULT 0, time_limit_seconds INTEGER, question_count INTEGER DEFAULT 10, is_private BOOLEAN DEFAULT false, password TEXT, is_premium_only BOOLEAN DEFAULT false, status TEXT DEFAULT 'waiting' CHECK (status IN ('waiting', 'in_progress', 'finished', 'cancelled')), starts_at TIMESTAMP WITH TIME ZONE, ended_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS live_game_players ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, game_id UUID REFERENCES live_games(id) ON DELETE CASCADE, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, is_ready BOOLEAN DEFAULT false, score INTEGER DEFAULT 0, correct_answers INTEGER DEFAULT 0, incorrect_answers INTEGER DEFAULT 0, avg_response_time_ms INTEGER, rank INTEGER, joined_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), left_at TIMESTAMP WITH TIME ZONE, UNIQUE(game_id, user_id) ); CREATE TABLE IF NOT EXISTS live_game_questions ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, game_id UUID REFERENCES live_games(id) ON DELETE CASCADE, question_number INTEGER NOT NULL, question_data JSONB NOT NULL, correct_answer TEXT NOT NULL, time_limit_seconds INTEGER, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS live_game_answers ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, game_id UUID REFERENCES live_games(id) ON DELETE CASCADE, player_id UUID REFERENCES live_game_players(id) ON DELETE CASCADE, question_id UUID REFERENCES live_game_questions(id) ON DELETE CASCADE, answer TEXT, is_correct BOOLEAN, response_time_ms INTEGER, points_earned INTEGER DEFAULT 0, answered_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(game_id, player_id, question_id) ); CREATE TABLE IF NOT EXISTS videos ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, course_id UUID REFERENCES courses(id) ON DELETE CASCADE, title TEXT NOT NULL, description TEXT, video_url TEXT NOT NULL, thumbnail_url TEXT, duration_seconds INTEGER, difficulty_level INTEGER DEFAULT 1, category TEXT, tags TEXT[] DEFAULT '{}', subtitles JSONB DEFAULT '{}', vocabulary_covered UUID[] DEFAULT '{}', is_active BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS user_video_progress ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, video_id UUID REFERENCES videos(id) ON DELETE CASCADE, progress_seconds INTEGER DEFAULT 0, is_completed BOOLEAN DEFAULT false, completed_at TIMESTAMP WITH TIME ZONE, last_watched_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), watch_count INTEGER DEFAULT 0, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(user_id, video_id) ); CREATE TABLE IF NOT EXISTS forum_categories ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, name TEXT NOT NULL, description TEXT, language_code TEXT, icon_name TEXT, display_order INTEGER DEFAULT 0, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS forum_posts ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, category_id UUID REFERENCES forum_categories(id) ON DELETE CASCADE, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, title TEXT NOT NULL, content TEXT NOT NULL, tags TEXT[] DEFAULT '{}', is_pinned BOOLEAN DEFAULT false, is_locked BOOLEAN DEFAULT false, view_count INTEGER DEFAULT 0, likes_count INTEGER DEFAULT 0, replies_count INTEGER DEFAULT 0, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS forum_replies ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, post_id UUID REFERENCES forum_posts(id) ON DELETE CASCADE, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, content TEXT NOT NULL, parent_id UUID REFERENCES forum_replies(id) ON DELETE SET NULL, likes_count INTEGER DEFAULT 0, is_solution BOOLEAN DEFAULT false, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS forum_post_likes ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, post_id UUID REFERENCES forum_posts(id) ON DELETE CASCADE, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(post_id, user_id) ); CREATE TABLE IF NOT EXISTS forum_reply_likes ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, reply_id UUID REFERENCES forum_replies(id) ON DELETE CASCADE, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), UNIQUE(reply_id, user_id) ); ALTER TABLE courses ENABLE ROW LEVEL SECURITY; ALTER TABLE lessons ENABLE ROW LEVEL SECURITY; ALTER TABLE vocabulary ENABLE ROW LEVEL SECURITY; ALTER TABLE grammar_rules ENABLE ROW LEVEL SECURITY; ALTER TABLE stories ENABLE ROW LEVEL SECURITY; ALTER TABLE practice_scenarios ENABLE ROW LEVEL SECURITY; ALTER TABLE user_learning_profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE user_lessons ENABLE ROW LEVEL SECURITY; ALTER TABLE user_vocabulary ENABLE ROW LEVEL SECURITY; ALTER TABLE user_grammar_progress ENABLE ROW LEVEL SECURITY; ALTER TABLE user_stories ENABLE ROW LEVEL SECURITY; ALTER TABLE user_scenario_attempts ENABLE ROW LEVEL SECURITY; ALTER TABLE pronunciation_attempts ENABLE ROW LEVEL SECURITY; ALTER TABLE user_streaks ENABLE ROW LEVEL SECURITY; ALTER TABLE streak_recovery_challenges ENABLE ROW LEVEL SECURITY; ALTER TABLE