n_attempts FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own streaks" ON user_streaks FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own streaks" ON user_streaks FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own recovery challenges" ON streak_recovery_challenges FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own recovery challenges" ON streak_recovery_challenges FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own quests" ON daily_quests FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own quests" ON daily_quests FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Quest definitions are viewable by everyone" ON quest_definitions FOR SELECT USING (true); CREATE POLICY "Only admins can modify quest definitions" ON quest_definitions FOR ALL USING (auth.uid() IN (SELECT user_id FROM admin_users)); CREATE POLICY "Achievements are viewable by everyone" ON achievements FOR SELECT USING (true); CREATE POLICY "Users can modify own achievements" ON achievements FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Achievement definitions are viewable by everyone" ON achievement_definitions FOR SELECT USING (true); CREATE POLICY "Only admins can modify achievement definitions" ON achievement_definitions FOR ALL USING (auth.uid() IN (SELECT user_id FROM admin_users)); CREATE POLICY "Weekly challenges are viewable by everyone" ON weekly_challenges FOR SELECT USING (true); CREATE POLICY "Only admins can modify weekly challenges" ON weekly_challenges FOR ALL USING (auth.uid() IN (SELECT user_id FROM admin_users)); CREATE POLICY "Users can view own weekly challenges" ON user_weekly_challenges FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own weekly challenges" ON user_weekly_challenges FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own AI conversations" ON ai_conversations FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own AI conversations" ON ai_conversations FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own AI sessions" ON ai_conversation_sessions FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own AI sessions" ON ai_conversation_sessions FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own analytics" ON learning_analytics FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own analytics" ON learning_analytics FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own reports" ON weekly_reports FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own reports" ON weekly_reports FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Users can view own heatmap" ON skill_heatmap FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own heatmap" ON skill_heatmap FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Activities viewable by friends" ON friend_activities FOR SELECT USING ( auth.uid() = user_id OR auth.uid() IN ( SELECT friend_id FROM friends WHERE user_id = friend_activities.user_id AND status = 'accepted' UNION SELECT user_id FROM friends WHERE friend_id = friend_activities.user_id AND status = 'accepted' ) ); CREATE POLICY "Users can create own activities" ON friend_activities FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can delete own activities" ON friend_activities FOR DELETE USING (auth.uid() = user_id); CREATE POLICY "Activity likes are viewable by everyone" ON activity_likes FOR SELECT USING (true); CREATE POLICY "Users can like activities" ON activity_likes FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can unlike activities" ON activity_likes FOR DELETE USING (auth.uid() = user_id); CREATE POLICY "Activity comments are viewable by everyone" ON activity_comments FOR SELECT USING (true); CREATE POLICY "Users can comment on activities" ON activity_comments FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can modify own comments" ON activity_comments FOR UPDATE USING (auth.uid() = user_id); CREATE POLICY "Users can delete own comments" ON activity_comments FOR DELETE USING (auth.uid() = user_id); CREATE POLICY "Live games are viewable by everyone" ON live_games FOR SELECT USING (true); CREATE POLICY "Authenticated users can create games" ON live_games FOR INSERT WITH CHECK (auth.uid() = host_id); CREATE POLICY "Host can modify their games" ON live_games FOR UPDATE USING (auth.uid() = host_id); CREATE POLICY "Host can delete their games" ON live_games FOR DELETE USING (auth.uid() = host_id); CREATE POLICY "Players can view game participants" ON live_game_players FOR SELECT USING ( auth.uid() = user_id OR auth.uid() IN (SELECT host_id FROM live_games WHERE id = live_game_players.game_id) ); CREATE POLICY "Users can join games" ON live_game_players FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can update their game status" ON live_game_players FOR UPDATE USING (auth.uid() = user_id); CREATE POLICY "Users can leave games" ON live_game_players FOR DELETE USING (auth.uid() = user_id); CREATE POLICY "Game questions viewable by participants" ON live_game_questions FOR SELECT USING ( auth.uid() IN (SELECT user_id FROM live_game_players WHERE game_id = live_game_questions.game_id) ); CREATE POLICY "Users can view own answers" ON live_game_answers FOR SELECT USING ( auth.uid() IN (SELECT user_id FROM live_game_players WHERE id = live_game_answers.player_id) OR auth.uid() IN (SELECT host_id FROM live_games WHERE id = live_game_answers.game_id) ); CREATE POLICY "Users can submit answers" ON live_game_answers FOR INSERT WITH CHECK (auth.uid() IN (SELECT user_id FROM live_game_players WHERE id = live_game_answers.player_id)); CREATE POLICY "Videos are viewable by everyone" ON videos FOR SELECT USING (true); CREATE POLICY "Only admins can modify videos" ON videos FOR ALL USING (auth.uid() IN (SELECT user_id FROM admin_users)); CREATE POLICY "Users can view own video progress" ON user_video_progress FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own video progress" ON user_video_progress FOR ALL USING (auth.uid() = user_id); CREATE POLICY "Forum categories are viewable by everyone" ON forum_categories FOR SELECT USING (true); CREATE POLICY "Only admins can modify categories" ON forum_categories FOR ALL USING (auth.uid() IN (SELECT user_id FROM admin_users)); CREATE POLICY "Forum posts are viewable by everyone" ON forum_posts FOR SELECT USING (true); CREATE POLICY "Authenticated users can create posts" ON forum_posts FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can modify own posts" ON forum_posts FOR UPDATE USING (auth.uid() = user_id); CREATE POLICY "Users can delete own posts" ON forum_posts FOR DELETE USING (auth.uid() = user_id); CREATE POLICY "Forum replies are viewable by everyone" ON forum_replies FOR SELECT USING (true); CREATE POLICY "Authenticated users can create replies" ON forum_replies FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can modify own replies" ON forum_replies FOR UPDATE USING (auth.uid() = user_id); CREATE POLICY "Users can delete own replies" ON forum_replies FOR DELETE USING (auth.uid() = user_id); CREATE POLICY "Forum post likes are viewable by everyone" ON forum_post_likes FOR SELECT USING (true); CREATE POLICY "Authenticated users can like posts" ON forum_post_likes FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can unlike posts" ON forum_post_likes FOR DELETE USING (auth.uid() = user_id); CREATE POLICY "Forum reply likes are viewable by everyone" ON forum_reply_likes FOR SELECT USING (true); CREATE POLICY "Authenticated users can like replies" ON forum_reply_likes FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can unlike replies" ON forum_reply_likes FOR DELETE USING (auth.uid() = user_id); CREATE INDEX idx_user_lessons_user_id ON user_lessons(user_id); CREATE INDEX idx_user_lessons_lesson_id ON user_lessons(lesson_id); CREATE INDEX idx_user_vocabulary_user_id ON user_vocabulary(user_id); CREATE INDEX idx_user_vocabulary_next_review ON user_vocabulary(next_review_at); CREATE INDEX idx_user_vocabulary_mastery ON user_vocabulary(mastery_level); CREATE INDEX idx_user_stories_user_id ON user_stories(user_id); CREATE INDEX idx_user_grammar_user_id ON user_grammar_progress(user_id); CREATE INDEX idx_user_streaks_user_id ON user_streaks(user_id); CREATE INDEX idx_daily_quests_user_date ON daily_quests(user_id, quest_date); CREATE INDEX idx_achievements_user_id ON achievements(user_id); CREATE INDEX idx_weekly_challenges_dates ON weekly_challenges(week_start_date, week_end_date); CREATE INDEX idx_learning_analytics_user_date ON learning_analytics(user_id, date); CREATE INDEX idx_weekly_reports_user_week ON weekly_reports(user_id, week_start_date); CREATE INDEX idx_skill_heatmap_user ON skill_heatmap(user_id, skill_category); CREATE INDEX idx_friend_activities_user_id ON friend_activities(user_id); CREATE INDEX idx_friend_activities_created ON friend_activities(created_at DESC); CREATE INDEX idx_activity_likes_activity_id ON activity_likes(activity_id); CREATE INDEX idx_activity_comments_activity_id ON activity_comments(activity_id); CREATE INDEX idx_live_games_status ON live_games(status); CREATE INDEX idx_live_games_language ON live_games(language_code); CREATE INDEX idx_live_game_players_game_id ON live_game_players(game_id); CREATE INDEX idx_live_game_players_user_id ON live_game_players(user_id); CREATE INDEX idx_lessons_course_id ON lessons(course_id); CREATE INDEX idx_vocabulary_course_id ON vocabulary(course_id); CREATE INDEX idx_vocabulary_difficulty ON vocabulary(difficulty_level); CREATE INDEX idx_stories_course_id ON stories(course_id); CREATE INDEX idx_videos_course_id ON videos(course_id); CREATE INDEX idx_forum_posts_category_id ON forum_posts(category_id); CREATE INDEX idx_forum_posts_created ON forum_posts(created_at DESC); CREATE INDEX idx_forum_replies_post_id ON forum_replies(post_id); CREATE OR REPLACE FUNCTION update_user_streak(p_user_id UUID) RETURNS VOID AS $$ DECLARE v_last_date DATE; v_current_streak INTEGER; v_today DATE := CURRENT_DATE; BEGIN SELECT last_streak_date, current_streak INTO v_last_date, v_current_streak FROM user_streaks WHERE user_id = p_user_id; IF v_last_date IS NULL THEN INSERT INTO user_streaks (user_id, current_streak, longest_streak, last_streak_date) VALUES (p_user_id, 1, 1, v_today); ELSIF v_last_date = v_today THEN NULL; ELSIF v_last_date = v_today - INTERVAL '1 day' THEN UPDATE user_streaks SET current_streak = current_streak + 1, longest_streak = GREATEST(longest_streak, current_streak + 1), last_streak_date = v_today, updated_at = NOW() WHERE user_id = p_user_id; ELSE IF EXISTS ( SELECT 1 FROM user_streaks WHERE user_id = p_user_id AND streak_freeze_count > 0 AND NOT (v_last_date = ANY(freeze_used_dates)) ) THEN UPDATE user_streaks SET streak_freeze_count = streak_freeze_count - 1, freeze_used_dates = array_append(freeze_used_dates, v_last_date + INTERVAL '1 day'), last_streak_date = v_today, updated_at = NOW() WHERE user_id = p_user_id; ELSE UPDATE user_streaks SET current_streak = 1, last_streak_date = v_today, updated_at = NOW() WHERE user_id = p_user_id; END IF; END IF; END; $$ LANGUAGE plpgsql; CREATE OR REPLACE FUNCTION calculate_next_review( p_ease_factor REAL, p_interval_days INTEGER, p_quality INTEGER ) RETURNS TABLE(next_review TIMESTAMP WITH TIME ZONE, new_ease_factor REAL, new_interval INTEGER) AS $$ DECLARE v_new_ease_factor REAL; v_new_interval INTEGER; BEGIN v_new_ease_factor := p_ease_factor + (0.1 - (5 - p_quality) * (0.08 + (5 - p_quality) * 0.02)); IF v_new_ease_factor < 1.3 THEN v_new_ease_factor := 1.3; END IF; IF p_quality < 3 THEN v_new_interval := 1; ELSIF p_interval_days = 0 THEN v_new_interval := 1; ELSIF p_interval_days = 1 THEN v_new_interval := 6; ELSE v_new_interval := ROUND(p_interval_days * v_new_ease_factor); END IF; RETURN QUERY SELECT NOW() + (v_new_interval || ' days')::INTERVAL, v_new_ease_factor, v_new_interval; END; $$ LANGUAGE plpgsql; CREATE OR REPLACE FUNCTION generate_daily_quests(p_user_id UUID) RETURNS VOID AS $$ DECLARE v_today DATE := CURRENT_DATE; v_existing_quests INTEGER; BEGIN SELECT COUNT(*) INTO v_existing_quests FROM daily_quests WHERE user_id = p_user_id AND quest_date = v_today; IF v_existing_quests = 0 THEN INSERT INTO daily_quests (user_id, quest_date, quests) SELECT p_user_id, v_today, jsonb_agg( jsonb_build_object( 'id', gen_random_uuid(), 'definition_id', id, 'title', title, 'description', description, 'type', quest_type, 'requirement', requirement_value, 'progress', 0, 'completed', false, 'reward_xp', reward_xp, 'reward_gems', reward_gems, 'difficulty', difficulty ) ) FROM ( SELECT * FROM quest_definitions WHERE is_active = true ORDER BY RANDOM() LIMIT 3 ) sub; END IF; END; $$ LANGUAGE plpgsql; CREATE OR REPLACE FUNCTION record_learning_activity( p_user_id UUID, p_activity_type TEXT, p_activity_data JSONB ) RETURNS VOID AS $$ BEGIN PERFORM update_user_streak(p_user_id); INSERT INTO friend_activities (user_id, activity_type, activity_data) VALUES (p_user_id, p_activity_type, p_activity_data); END; $$ LANGUAGE plpgsql; CREATE OR REPLACE FUNCTION update_updated_at_column() RETURNS TRIGGER AS $$ BEGIN NEW.updated_at = NOW(); RETURN NEW; END; $$ LANGUAGE plpgsql; CREATE TRIGGER update_courses_updated_at BEFORE UPDATE ON courses FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_lessons_updated_at BEFORE UPDATE ON lessons FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_vocabulary_updated_at BEFORE UPDATE ON vocabulary FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_grammar_rules_updated_at BEFORE UPDATE ON grammar_rules FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_stories_updated_at BEFORE UPDATE ON stories FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_user_learning_profiles_updated_at BEFORE UPDATE ON user_learning_profiles FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_user_lessons_updated_at BEFORE UPDATE ON user_lessons FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_user_vocabulary_updated_at BEFORE UPDATE ON user_vocabulary FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_user_grammar_progress_updated_at BEFORE UPDATE ON user_grammar_progress FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_user_stories_updated_at BEFORE UPDATE ON user_stories FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_user_streaks_updated_at BEFORE UPDATE ON user_streaks FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_daily_quests_updated_at BEFORE UPDATE ON daily_quests FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_user_weekly_challenges_updated_at BEFORE UPDATE ON user_weekly_challenges FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_ai_conversation_sessions_updated_at BEFORE UPDATE ON ai_conversation_sessions FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_skill_heatmap_updated_at BEFORE UPDATE ON skill_heatmap FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_activity_comments_updated_at BEFORE UPDATE ON activity_comments FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_live_games_updated_at BEFORE UPDATE ON live_games FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_videos_updated_at BEFORE UPDATE ON videos FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_forum_posts_updated_at BEFORE UPDATE ON forum_posts FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE TRIGGER update_forum_replies_updated_at BEFORE UPDATE ON forum_replies FOR EACH ROW EXECUTE FUNCTION update_updated_at_column(); CREATE OR REPLACE FUNCTION update_post_reply_count() RETURNS TRIGGER AS $$ BEGIN IF TG_OP = 'INSERT' THEN UPDATE forum_posts SET replies_count = replies_count + 1 WHERE id = NEW.post_id; ELSIF TG_OP = 'DELETE' THEN UPDATE forum_posts SET replies_count = replies_count - 1 WHERE id = OLD.post_id; END IF; RETURN NULL; END; $$ LANGUAGE plpgsql; CREATE TRIGGER forum_post_reply_count_trigger AFTER INSERT OR DELETE ON forum_replies FOR EACH ROW EXECUTE FUNCTION update_post_reply_count(); INSERT INTO quest_definitions (title, description, quest_type, requirement_value, reward_xp, reward_gems, difficulty) VALUES ('Lesson Learner', 'Complete 2 lessons today', 'complete_lessons', 2, 15, 0, 'easy'), ('XP Hunter', 'Earn 50 XP today', 'earn_xp', 50, 20, 0, 'easy'), ('Vocabulary Master', 'Review 10 vocabulary words', 'practice_vocab', 10, 15, 0, 'easy'), ('Streak Keeper', 'Maintain your streak', 'streak', 1, 10, 0, 'easy'), ('Social Butterfly', 'Send a message to a friend', 'social', 1, 10, 0, 'easy'), ('Grammar Guru', 'Complete 1 grammar exercise', 'complete_lessons', 1, 15, 0, 'medium'), ('Big XP Day', 'Earn 100 XP today', 'earn_xp', 100, 30, 5, 'medium'), ('Pronunciation Pro', 'Practice pronunciation 5 times', 'practice_vocab', 5, 20, 0, 'medium'), ('Story Explorer', 'Complete 1 story', 'complete_lessons', 1, 25, 0, 'medium'), ('Marathon Monday', 'Study for 30 minutes', 'earn_xp', 30, 40, 10, 'hard'), ('Perfect Score', 'Get 100% on any lesson', 'complete_lessons', 1, 50, 15, 'hard'), ('Vocabulary Champion', 'Learn 20 new words', 'practice_vocab', 20, 40, 10, 'hard'); INSERT INTO achievement_definitions (id, title, description, category, tiers) VALUES ('vocab_100', 'Word Collector', 'Learn 100 vocabulary words', 'learning', '[{"tier": "bronze", "requirement": 10, "reward": 50}, {"tier