tier": "bronze", "requirement": 1, "reward": 15}, {"tier": "silver", "requirement": 5, "reward": 40}, {"tier": "gold", "requirement": 20, "reward": 100}, {"tier": "platinum", "requirement": 100, "reward": 300}]'), ('night_owl', 'Night Owl', 'Study after 10 PM', 'consistency', '[{"tier": "bronze", "requirement": 1, "reward": 15}, {"tier": "silver", "requirement": 5, "reward": 40}, {"tier": "gold", "requirement": 20, "reward": 100}, {"tier": "platinum", "requirement": 100, "reward": 300}]'); INSERT INTO forum_categories (name, description, icon_name, display_order) VALUES ('General Discussion', 'General language learning discussions', 'chat', 1), ('Grammar Help', 'Get help with grammar questions', 'school', 2), ('Vocabulary', 'Discuss vocabulary and word meanings', 'book', 3), ('Pronunciation', 'Share pronunciation tips and get feedback', 'mic', 4), ('Cultural Exchange', 'Learn about different cultures', 'public', 5), ('Study Tips', 'Share and discover study strategies', 'lightbulb', 6), ('Success Stories', 'Share your language learning journey', 'emoji_events', 7), ('Beginners', 'Questions and support for beginners', 'person', 8); CREATE TABLE IF NOT EXISTS user_profiles_extended ( id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE UNIQUE, learning_style TEXT CHECK (learning_style IN ('visual', 'auditory', 'kinesthetic', 'reading_writing', 'mixed')), current_theme TEXT DEFAULT 'default', is_dark_mode BOOLEAN DEFAULT false, is_oled_mode BOOLEAN DEFAULT false, notification_preferences JSONB DEFAULT '{}', study_reminder_time TIME, widget_config JSONB DEFAULT '{}', created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() ); ALTER TABLE user_profiles_extended ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users can view own profile extended" ON user_profiles_extended FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can modify own profile extended" ON user_profiles_extended FOR ALL USING (auth.uid() = user_id); CREATE TRIGGER update_user_profiles_extended_updated_at BEFORE UPDATE ON user_profiles_extended FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();